$repo='https://github.com/TabotCharlesBessong/advanced_database'
$issues=@(
[pscustomobject]@{title='P2 Storage: Storage config and page size constants'; body='## Parent Epic`nPhase 2 (Weeks 5-6): Data Storage Foundation`n`n## Scope`nDefine storage-wide constants and configuration for page and file behavior.`n`n## Tasks`n- Add page size constant(s) (4KB/8KB selectable)`n- Define storage config struct/class`n- Add defaults and override path for tests`n- Document configuration options`n`n## Acceptance Criteria`n- Config compiles and is consumed by storage components`n- Unit test confirms default and override values'}
[pscustomobject]@{title='P2 Storage: FileManager create/open/read/write/flush API'; body='## Parent Epic`nPhase 2 (Weeks 5-6): Data Storage Foundation`n`n## Scope`nImplement low-level file operations abstraction for storage layer.`n`n## Tasks`n- Implement create/open/close file APIs`n- Implement page read/write by offset`n- Implement flush/sync behavior`n- Return clear error codes/messages`n`n## Acceptance Criteria`n- Read/write roundtrip test passes`n- Flush persists data across process restart'}
[pscustomobject]@{title='P2 Storage: Page struct and page header format'; body='## Parent Epic`nPhase 2 (Weeks 5-6): Data Storage Foundation`n`n## Scope`nDefine in-memory and on-disk page layout/header format.`n`n## Tasks`n- Define page header fields (id, flags, checksum/version)`n- Define payload boundaries`n- Add helpers for header encode/decode`n- Document binary layout`n`n## Acceptance Criteria`n- Header serialization tests pass`n- Backward-compatible version marker is present'}
