[pscustomobject]@{title='P2 Parser: Parser for SELECT + simple WHERE'; body='## Parent Epic`nPhase 2 (Weeks 11-12): SQL Parser Foundation`n`n## Scope`nImplement parser branch for SELECT with simple filters.`n`n## Tasks`n- Parse select-list and FROM table`n- Parse equality WHERE expressions`n- Build SELECT AST nodes`n`n## Acceptance Criteria`n- SELECT and SELECT+WHERE parse correctly`n- Unsupported clauses fail gracefully'}
[pscustomobject]@{title='P2 Parser: Parser diagnostics (line/column) + negative test corpus'; body='## Parent Epic`nPhase 2 (Weeks 11-12): SQL Parser Foundation`n`n## Scope`nImprove parser diagnostics and test failure cases.`n`n## Tasks`n- Emit line/column in parse errors`n- Add clear expected-token messaging`n- Add negative corpus of malformed SQL inputs`n`n## Acceptance Criteria`n- Error messages are consistent and precise`n- Negative parser test suite passes'}
)
$links = $issues | ForEach-Object {
  $title=[uri]::EscapeDataString($_.title)
  $body=[uri]::EscapeDataString($_.body)
  "$repo/issues/new?title=$title&body=$body"
}
$links | Set-Content -Path 'phase2-child-issue-links.txt'
$links